  letter-spacing: -0.02em;
  max-width: 22ch;
  margin-inline: auto;
  line-height: 1.1;
}
.cta-inner p { margin-top: 1.1rem; color: var(--gray-400); max-width: 50ch; margin-inline: auto; }
.cta-inner .btn { margin-top: 2.2rem; }

/* ---------- Contact ---------- */
.contact-grid { display: grid; grid-template-columns: 1fr 1.1fr; gap: clamp(2.5rem, 6vw, 5rem); }
.contact-info .section-title { margin-top: 0.8rem; }
.contact-info > p { margin-top: 1.2rem; color: var(--gray-600); max-width: 42ch; }
.contact-details { margin-top: 2.2rem; display: grid; gap: 1.1rem; }
.contact-details li { display: flex; flex-direction: column; gap: 0.2rem; border-top: 1px solid var(--line); padding-top: 1rem; }
.contact-details span { font-size: 0.74rem; letter-spacing: 0.18em; text-transform: uppercase; color: var(--gray-400); }

/* ---------- Form ---------- */
.contact-form { display: grid; gap: 1.25rem; }
.field { display: grid; gap: 0.5rem; }
.field-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1.25rem; }
.field label { font-size: 0.8rem; letter-spacing: 0.06em; text-transform: uppercase; color: var(--gray-600); font-weight: 500; }
.field input, .field select, .field textarea {
  font-family: inherit;
  font-size: 1rem;
  color: var(--ink);
  background: var(--white);
  border: 1px solid var(--gray-200);
  border-radius: 4px;
  padding: 0.85rem 1rem;
  transition: border-color 0.25s var(--ease), box-shadow 0.25s var(--ease);
}
.field input:focus, .field select:focus, .field textarea:focus {
  outline: none; border-color: var(--black); box-shadow: 0 0 0 3px rgba(10, 10, 10, 0.08);
}
.field textarea { resize: vertical; }
.field.invalid input, .field.invalid select, .field.invalid textarea { border-color: #b00020; }
.form-status { font-size: 0.95rem; font-weight: 500; min-height: 1.2em; }
.form-status.ok { color: #0a7d2c; }
.form-status.err { color: #b00020; }
.form-note { font-size: 0.8rem; color: var(--gray-400); }

/* ---------- Footer ---------- */
.site-footer { background: var(--black); color: var(--white); padding-top: clamp(3.5rem, 7vw, 5.5rem); }
.footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 2.5rem; padding-bottom: 3.5rem; }
.footer-brand .brand-mark { color: var(--white); }
.footer-brand p { margin-top: 1rem; color: var(--gray-400); max-width: 34ch; font-size: 0.95rem; }
.footer-col h4 { font-size: 0.78rem; letter-spacing: 0.18em; text-transform: uppercase; color: var(--gray-400); margin-bottom: 1rem; }
.footer-col a { display: block; padding: 0.35rem 0; color: #d4d4d4; font-size: 0.95rem; transition: color 0.25s var(--ease); }
.footer-col a:hover { color: var(--white); }
.footer-bottom {
  display: flex; justify-content: space-between; flex-wrap: wrap; gap: 0.75rem;
  padding-block: 1.8rem; border-top: 1px solid rgba(255, 255, 255, 0.14);
  color: var(--gray-400); font-size: 0.85rem;
}

/* ---------- Scroll reveal ---------- */
.reveal { opacity: 0; transform: translateY(24px); transition: opacity 0.7s var(--ease), transform 0.7s var(--ease); }
.reveal.is-visible { opacity: 1; transform: none; }
@media (prefers-reduced-motion: reduce) {
  .reveal { opacity: 1; transform: none; transition: none; }
  html { scroll-behavior: auto; }
}

/* ---------- Responsive ---------- */
@media (max-width: 900px) {
  .nav, .nav-cta { display: none; }
  .nav-toggle { display: flex; }
  .cards { grid-template-columns: repeat(2, 1fr); }
  .steps { grid-template-columns: repeat(2, 1fr); }
  .about-grid { grid-template-columns: 1fr; }
  .about-media { order: -1; }
  .contact-grid { grid-template-columns: 1fr; }
  .footer-grid { grid-template-columns: 1fr 1fr; }
}

@media (max-width: 560px) {
  .cards { grid-template-columns: 1fr; }
  .steps { grid-template-columns: 1fr; }
  .field-row { grid-template-columns: 1fr; }
  .footer-grid { grid-template-columns: 1fr; gap: 2rem; }
  .hero-stats { gap: 1.75rem; }
  .stat { flex: 1 1 40%; }
  .btn { width: 100%; }
  .hero-actions { flex-direction: column; }
}
